from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an artist into a fluent natural‑language description.
    """
    if not triples:
        return ""

    # Group triples by subject and collect objects per predicate
    # Build a map from each subject to its predicates/objects
    subj_map: dict[str, dict[str, list[str]]] = {}
    for t in triples:
        subj_map.setdefault(t.subject, {}).setdefault(t.predicate, []).append(t.object)

    # Build a secondary map for predicates that relate one entity to another
    # (e.g., genre → musicFusionGenre → fusion genre)
    relation_predicates = {
        "musicFusionGenre",
        "musicSubgenre",
        "derivative",
        "stylisticOrigin",
    }
    relation_map: dict[str, list[tuple[str, str]]] = {}
    for t in triples:
        if t.predicate in relation_predicates:
            relation_map.setdefault(t.subject, []).append((t.predicate, t.object))

    sentences: list[str] = []

    for subj, preds in subj_map.items():
        parts: list[str] = []

        # Background (e.g., "solo singer", "non vocal instrumentalist")
        if "background" in preds:
            bg = preds["background"][0].strip('"')
            parts.append(f"{subj} is a {bg}")

        else:
            parts.append(subj)

        # Origin / birth place / nationality
        if "origin" in preds:
            parts.append(f"originates from {preds['origin'][0]}")
        elif "birthPlace" in preds:
            parts.append(f"was born in {preds['birthPlace'][0]}")
        if "nationality" in preds:
            parts.append(f"is {preds['nationality'][0]}")

        # Birth date
        if "birthDate" in preds:
            parts.append(f"born on {preds['birthDate'][0]}")

        # Genre
        if "genre" in preds:
            genre = preds["genre"][0]
            parts.append(f"performs {genre} music")
            # Add any known relations where this genre is the subject
            if genre in relation_map:
                for rel_pred, rel_obj in relation_map[genre]:
                    if rel_pred == "musicFusionGenre":
                        parts.append(f"which has a fusion genre {rel_obj}")
                    elif rel_pred == "musicSubgenre":
                        parts.append(f"which includes the subgenre {rel_obj}")
                    elif rel_pred == "derivative":
                        parts.append(f"which is a derivative of {rel_obj}")
                    elif rel_pred == "stylisticOrigin":
                        parts.append(f"originating from {rel_obj}")

        # Instrument
        if "instrument" in preds:
            parts.append(f"plays the {preds['instrument'][0]}")

        # Active years
        if "activeYearsStartYear" in preds:
            parts.append(f"started their career in {preds['activeYearsStartYear'][0]}")
        if "activeYearsEndYear" in preds:
            parts.append(f"ended their career in {preds['activeYearsEndYear'][0]}")

        # Associated artists / bands
        if "associatedBand/associatedMusicalArtist" in preds:
            assoc = preds["associatedBand/associatedMusicalArtist"]
            if len(assoc) == 1:
                parts.append(f"is associated with {assoc[0]}")
            else:
                assoc_str = ", ".join(assoc[:-1]) + f", and {assoc[-1]}"
                parts.append(f"is associated with {assoc_str}")

        # Record label (may have multiple)
        if "recordLabel" in preds:
            labels = preds["recordLabel"]
            if len(labels) == 1:
                parts.append(f"is signed to {labels[0]}")
            else:
                label_str = ", ".join(labels[:-1]) + f", and {labels[-1]}"
                parts.append(f"is signed to {label_str}")

        # Handle any remaining predicates in a generic way
        generic_skip = {
            "background", "origin", "birthPlace", "nationality", "birthDate",
            "genre", "instrument", "activeYearsStartYear", "activeYearsEndYear",
            "associatedBand/associatedMusicalArtist", "recordLabel"
        }
        for pred, objs in preds.items():
            if pred in generic_skip:
                continue
            for obj in objs:
                parts.append(f"{pred.replace('_', ' ')} {obj}")

        sentence = ", ".join(parts) + "."
        sentences.append(sentence)

    # Combine sentences for different subjects
    if len(sentences) == 1:
        return sentences[0]
    else:
        return " ".join(sentences)

# EVOLVE-BLOCK-END

